// Sélection du sujet d'article à générer
const sujets = [
  { motCle: 'meilleur écran pc 2025', categorie: 'PC & Laptops', type: 'comparatif', budget: '150-600€' },
  { motCle: 'meilleur clavier mécanique', categorie: 'PC & Laptops', type: 'comparatif', budget: '50-200€' },
  { motCle: 'meilleure souris gaming', categorie: 'PC & Laptops', type: 'top5', budget: '30-150€' },
  { motCle: 'meilleur smartphone android 2025', categorie: 'Smartphones', type: 'comparatif', budget: '300-800€' },
  { motCle: 'meilleurs écouteurs sans fil', categorie: 'Audio & Casques', type: 'comparatif', budget: '50-300€' },
  { motCle: 'meilleur disque dur externe', categorie: 'Stockage', type: 'guide', budget: '40-150€' },
  { motCle: 'meilleur routeur wifi 6', categorie: 'Réseau', type: 'comparatif', budget: '60-250€' },
  { motCle: 'meilleure webcam streaming', categorie: 'Accessoires', type: 'top5', budget: '50-200€' },
  { motCle: 'meilleur SSD NVMe 2025', categorie: 'Stockage', type: 'comparatif', budget: '60-200€' },
  { motCle: 'meilleur PC bureau gaming', categorie: 'PC & Laptops', type: 'guide-achat', budget: '800-2000€' }
];

// Choisir un sujet aléatoire ou utiliser l'input webhook
const inputData = $input.first()?.json;
let sujet;

if (inputData?.motCle) {
  sujet = {
    motCle: inputData.motCle,
    categorie: inputData.categorie || 'Tech',
    type: inputData.type || 'comparatif',
    budget: inputData.budget || '50-500€'
  };
} else {
  sujet = sujets[Math.floor(Math.random() * sujets.length)];
}

const timestamp = new Date().toISOString();
const slug = sujet.motCle.toLowerCase().replace(/[éèê]/g, 'e').replace(/[àâ]/g, 'a').replace(/[ùû]/g, 'u').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

return [{
  json: {
    ...sujet,
    slug,
    timestamp,
    tagAffilié: 'techconseils-21'
  }
}];

const response = $input.first().json;
const sujet = $('📋 Préparer le sujet').first().json;

// Extraire le contenu de la réponse Claude
const content = response.content?.[0]?.text || '';

// Séparer l'article du JSON
const parts = content.split('---JSON---');
const articleMarkdown = parts[0].trim();
let metadata = {};

try {
  if (parts[1]) {
    const jsonStr = parts[1].trim().replace(/```json|```/g, '').trim();
    metadata = JSON.parse(jsonStr);
  }
} catch(e) {
  console.log('Parsing JSON metadata failed:', e.message);
}

// Construire l'objet article final
const article = {
  slug: metadata.slug || sujet.slug,
  titre: metadata.titre || `Meilleur ${sujet.motCle} 2025`,
  metaDescription: metadata.metaDescription || '',
  categorie: metadata.categorie || sujet.categorie,
  tags: metadata.tags || [sujet.motCle, 'comparatif', 'guide achat'],
  contenu: articleMarkdown,
  produits: metadata.produits || [],
  datePublication: new Date().toISOString(),
  statut: 'brouillon',
  mentionLegale: 'En tant que Partenaire Amazon, je réalise un bénéfice sur les achats remplissant les conditions requises.',
  motCle: sujet.motCle,
  tagAffilié: sujet.tagAffilié,
  wordCount: articleMarkdown.split(/\s+/).length
};

console.log(`✅ Article généré : ${article.titre} (${article.wordCount} mots)`);

return [{ json: article }];

const article = $input.first().json;

// Simuler la sauvegarde (remplacer par appel API WordPress réel)
const wordpressPayload = {
  title: article.titre,
  content: article.contenu,
  status: 'draft',
  slug: article.slug,
  categories: [article.categorie],
  tags: article.tags,
  meta: {
    _yoast_wpseo_metadesc: article.metaDescription,
    _yoast_wpseo_focuskw: article.motCle
  }
};

// Log pour vérification
console.log('📤 Publication WordPress (simulation):');
console.log('Titre:', article.titre);
console.log('Slug:', article.slug);
console.log('Mots:', article.wordCount);
console.log('Produits:', article.produits.length);

return [{
  json: {
    ...article,
    wordpressPayload,
    status: 'ready_to_publish',
    message: `✅ Article "${article.titre}" prêt à publier (${article.wordCount} mots, ${article.produits.length} produits)`
  }
}];

const article = $input.first().json;

// Résumé de l'échec qualité
return [{
  json: {
    status: 'quality_failed',
    slug: article.slug,
    wordCount: article.wordCount,
    message: `❌ Article "${article.titre}" rejeté : ${article.wordCount} mots (minimum 800 requis). Relancer la génération.`
  }
}];
